    hexi::binary_stream<std::span<const uint8_t>> stream(adaptor);
    stream >> item_count;

    // Check if buffer has enough data for the items
    size_t required_size = 1 + sizeof(uint32_t); // data_type + item_count
    required_size += (data_type == 0) ? (item_count * sizeof(uint32_t)) 
                                     : (item_count * sizeof(float));

    if (adaptor.size() < required_size) {
