#include <hexi/allocators/block_allocator.h>
#include <cstdint>
#include <iostream>

template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    // Create a block_allocator instance
    hexi::block_allocator<int, element_count> allocator;

    std::cout << "Demonstrating block_allocator free list management with " 
              << element_count << " elements per block:\n";

    // Initial state: free list contains element_count blocks
    std::cout << "Initial free list size: " << element_count << " blocks\n";

    // Demonstrate allocation (calls pop() internally)
    int* allocated_block = allocator.allocate();
    std::cout << "After allocate(): free list size reduced by 1\n";

    // Demonstrate deallocation (calls push() internally)
    allocator.deallocate(allocated_block);
    std::cout << "After deallocate(): free list size restored\n";

    // Show multiple allocation/deallocation cycles
    std::cout << "\nMultiple allocation/deallocation cycles:\n";

    for (size_t i = 0; i < element_count * 2; ++i) {
        // Alternate between allocation and deallocation
        if (i % 2 == 0) {
            int* block = allocator.allocate();
            std::cout << "Allocated block " << (i/2 + 1) << "\n";
            allocator.deallocate(block);
        } else {
            // For odd iterations, just show the state
            std::cout << "Free list state maintained through deallocate()\n";
        }
    }

    std::cout << "\nFinal demonstration: ";

    // Show that after element_count allocations, we need new blocks
    std::vector<int*> blocks;
    for (size_t i = 0; i < element_count; ++i) {
        int* block = allocator.allocate();
        blocks.push_back(block);
        std::cout << "Allocated block " << (i + 1) << " (";
        if (i < element_count - 1) std::cout << "still space in current block)";
        else std::cout << "last block in current allocation)";
    }

    // Deallocate all blocks
    for (auto block : blocks) {
        allocator.deallocate(block);
        std::cout << "\nDeallocated block";
    }

    std::cout << "\n\nFree list management principles demonstrated:\n"
              << "1. push() adds blocks to head of free list\n"
              << "2. pop() removes from head of free list\n"
              << "3. allocate() uses pop() to get next available block\n"
              << "4. deallocate() uses push() to return block to head\n"
              << "5. When free list is empty, new blocks are allocated\n";
}
```

