    hexi::endian::conditional_reverse_inplace<from, to>(value);
    return value;
}

template<typename T>
T convert_endianness_runtime(T value, std::endian from, std::endian to) {
    if (from == to) {
        return value;
    }

    switch (from) {
        case std::endian::native:
            return hexi::endian::native_to_big(value);
        case std::endian::big:
            return hexi::endian::be32to64(value);
        case std::endian::little:
            return hexi::endian::le32to64(value);
        default:
            // For unsupported endianness, return original value
            return value;
    }
}
