```cpp
#include <hexi/endian.h>
#include <cstdint>
#include <bit>

template<typename T>
void convert_from_big_endian_inplace(T& value) {
    // Check if native endianness is big endian
    if constexpr (std::endian::native == std::endian::big) {
        // No conversion needed if already big endian
        return;
    }

    // Use hexi::endian::be::from() to convert from big endian to native
    value = hexi::endian::be::from(value);
}

template<typename T>
void convert_from_little_endian_inplace(T& value) {
    // Check if native endianness is little endian
    if constexpr (std::endian::native == std::endian::little) {
        // No conversion needed if already little endian
        return;
    }

    // Use hexi::endian::le::from() to convert from little endian to native
    value = hexi::endian::le::from(value);
}

template<std::endian from, std::endian to, typename T>
void convert_endianness_inplace(T& value) {
    // Use hexi::endian::storage_in() to convert to intermediate storage format
    auto intermediate = hexi::endian::storage_in(value);

    // Use hexi::endian::storage_out() to convert to target endianness
    value = hexi::endian::storage_out(intermediate);
}
```

## Key Implementation Points:

1. **`convert_from_big_endian_inplace`**:
   - Uses compile-time check with `if constexpr` to avoid unnecessary operations
   - Directly uses `hexi::endian::be::from()` for conversion when needed

2. **`convert_from_little_endian_inplace`**:
   - Similar approach to big endian conversion
   - Uses `hexi::endian::le::from()` for little endian to native conversion

3. **`convert_endianness_inplace`**:
   - Implements the general case using the two-step process specified
   - First converts to storage format using `storage_in()`
   - Then converts from storage format to target using `storage_out()`

All functions modify the value directly in-place as required, and properly handle the edge case where no conversion is needed when source and target endianness match.

