#include <hexi/detail/intrusive_storage.h>
#include <vector>
#include <cstdint>
#include <stdexcept>

template<size_t block_size = 1024>
std::vector<uint8_t> preview_data_without_consuming(const hexi::detail::intrusive_storage<block_size>& storage, size_t bytes_to_preview) {
    // Create destination buffer
    std::vector<uint8_t> destination(bytes_to_preview);

    // Use copy method to copy data without advancing read pointer
    size_t bytes_copied = storage.copy(destination.data(), bytes_to_preview);

    // Verify we copied the expected amount of data
    if (bytes_copied != bytes_to_preview) {
        throw std::runtime_error("Failed to copy the requested number of bytes");
    }

    return destination;
}

template<size_t block_size = 1024>
struct BufferStatus {
    size_t readable_size;
    size_t free_space;
};

BufferStatus<> check_buffer_status(const hexi::detail::intrusive_storage<1024>& storage) {
    // Use size() method to get readable data size
    size_t readable_size = storage.size();

    // Calculate free space as block_size - write_offset
    // Note: write_offset is accessible through the storage object
    size_t free_space = 1024 - storage.write_offset;

    return BufferStatus<>{readable_size, free_space};
}

template<size_t block_size = 1024>
void reset_buffer(hexi::detail::intrusive_storage<block_size>& storage) {
    // Use clear() method to reset both read and write offsets
    storage.clear();
}
